-- ----------------------------------------------------------------------------
-- vw_rulebook_releases: Version ledger for the canonical ERB-PKO rulebook itself. This is distinct from PKO Procedure versioning.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_rulebook_releases CASCADE;
CREATE VIEW vw_rulebook_releases WITH (security_invoker = ON) AS
SELECT
  t.rulebook_release_id,                                                        -- Stored logical identifier for one RulebookReleases row.
  calc_rulebook_releases_name(t.rulebook_release_id) AS name,                   -- Human-readable calculated display alias for the RulebookReleases row.
  t.rulebook_version,                                                           -- Semantic version of this canonical rulebook release.
  t.profile_version,                                                            -- Version of the ERB-PKO profile schema.
  t.profile_schema_path,                                                        -- Repository-relative path to the ERB-PKO JSON profile schema.
  t.pko_core_version_iri,                                                       -- Exact version IRI of the PKO core ontology used by this release.
  t.pko_industry_version_iri,                                                   -- Exact version IRI of the PKO industry module used by this release.
  t.issued_at,                                                                  -- Timestamp at which this rulebook release was issued.
  t.status,                                                                     -- Release status such as Draft, Candidate, or Published.
  t.changelog,                                                                  -- Human-readable semantic changelog for this release.
  t.is_current                                                                  -- TRUE only for the current rulebook release.
FROM rulebook_releases t;

-- ----------------------------------------------------------------------------
-- vw_ontology_profiles: Versioned ontology and vocabulary dependencies. PKO mappings always identify the exact profile and version.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_ontology_profiles CASCADE;
CREATE VIEW vw_ontology_profiles WITH (security_invoker = ON) AS
SELECT
  t.ontology_profile_id,                                                        -- Stored logical identifier for one OntologyProfiles row.
  calc_ontology_profiles_name(t.ontology_profile_id) AS name,                   -- Human-readable calculated display alias for the OntologyProfiles row.
  t.label,                                                                      -- Human-readable ontology or vocabulary name.
  t.version,                                                                    -- Referenced release or specification version.
  t.version_iri,                                                                -- Exact version IRI or normative specification URI.
  t.namespace_iri,                                                              -- Namespace used for class/property IRIs.
  t.license,                                                                    -- License or standards body attribution.
  t.scope                                                                       -- How the profile is used in this rulebook.
FROM ontology_profiles t;

-- ----------------------------------------------------------------------------
-- vw_evaluation_contexts: The instant this rulebook's time-dependent witnesses are evaluated against. Modeled as data rather than wall-clock so every freshness, overdue, and validity answer is reproducible and auditable: asking the same question tomorrow yields the same answer. Exactly one row carries IsCurrent.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_evaluation_contexts CASCADE;
CREATE VIEW vw_evaluation_contexts WITH (security_invoker = ON) AS
SELECT
  t.evaluation_context_id,                                                      -- Stored logical identifier for one EvaluationContexts row.
  calc_evaluation_contexts_name(t.evaluation_context_id) AS name,               -- Human-readable calculated display alias for the EvaluationContexts row.
  t.label,                                                                      -- What this evaluation instant represents.
  t.as_of_instant,                                                              -- The instant all time-dependent witnesses are evaluated against.
  t.is_current,                                                                 -- TRUE for the single active evaluation context.
  t.rationale,                                                                  -- Why this instant was chosen.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM evaluation_contexts t;

