-- ----------------------------------------------------------------------------
-- vw_agents: Human and software agents that create, modify, approve, or execute procedural knowledge. Maps to prov:Agent.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_agents CASCADE;
CREATE VIEW vw_agents WITH (security_invoker = ON) AS
SELECT
  t.agent_id,                                                                   -- Stored logical identifier for one Agents row.
  calc_agents_name(t.agent_id) AS name,                                         -- Human-readable calculated display alias for the Agents row.
  t.display_name,                                                               -- Agent's human-readable name.
  t.agent_kind,                                                                 -- Human, AIAgent, AutomatedPipeline, Organization, or another explicit agent category.
  t.organization,                                                               -- Organization to which the agent belongs.
  t.contact_address,                                                            -- Contact address when applicable.
  t.version_or_employment_key,                                                  -- Model version, pipeline release, or employment assignment key.
  calc_agents_count_of_current_role_assignments(t.agent_id) AS count_of_current_role_assignments,-- How many role assignments this agent currently holds. Counts only CURRENT assignments via the CurrentAgentKey echo — counting all assignments would report a departed agent as engaged forever.
  calc_agents_is_still_engaged(t.agent_id) AS is_still_engaged,                 -- TRUE when this agent currently holds at least one role in the organization.
  calc_agents_decision_count(t.agent_id) AS decision_count,                     -- Total decisions this agent has recorded.
  calc_agents_overridden_decision_count(t.agent_id) AS overridden_decision_count,-- Decisions by this agent that a human corrected or reversed.
  calc_agents_override_rate_percent(t.agent_id) AS override_rate_percent,       -- Percentage of this agent's decisions that were overridden by a human.
  calc_agents_is_non_human(t.agent_id) AS is_non_human,                         -- TRUE when this agent is an AI agent or an automated pipeline.
  calc_agents_boundary_violation_count(t.agent_id) AS boundary_violation_count, -- Number of decisions by this agent that violated an authority boundary.
  calc_agents_is_operating_outside_boundary(t.agent_id) AS is_operating_outside_boundary,-- TRUE when this agent has made at least one decision an authority boundary forbids.
  calc_agents_draft_decision_count(t.agent_id) AS draft_decision_count,         -- Number of drafting decisions this agent has made.
  calc_agents_overridden_draft_count(t.agent_id) AS overridden_draft_count,     -- Number of this agent's drafting decisions a human corrected or reversed.
  calc_agents_draft_rewrite_rate_percent(t.agent_id) AS draft_rewrite_rate_percent,-- Percentage of this agent's drafting output that a human rewrote.
  t.semantic_type_iri                                                           -- Exact semantic type IRI used when projecting the agent.
FROM agents t;

-- ----------------------------------------------------------------------------
-- vw_roles: Stable organizational functions separated from the agents that currently fill them. Maps to pro:Role.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_roles CASCADE;
CREATE VIEW vw_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,                                                                    -- Stored logical identifier for one Roles row.
  calc_roles_name(t.role_id) AS name,                                           -- Human-readable calculated display alias for the Roles row.
  t.label,                                                                      -- Human-readable role label.
  t.organization,                                                               -- Organization that owns the role.
  t.current_agent,                                                              -- Current agent filling the role; history is retained in RoleAssignments.
  calc_roles_current_agent_kind(t.role_id) AS current_agent_kind,               -- Agent category of the current role filler.
  t.responsibility,                                                             -- Accountability and responsibility assigned to the role.
  calc_roles_active_assignment_count(t.role_id) AS active_assignment_count,     -- Total number of assignment rows ever recorded against this role.
  calc_roles_currently_covered_assignment_count(t.role_id) AS currently_covered_assignment_count,-- Number of assignment rows for this role that are in force right now.
  calc_roles_has_no_current_holder(t.role_id) AS has_no_current_holder,         -- TRUE when no assignment currently covers this role — the role is uncovered.
  calc_roles_count_of_awaited_decisions(t.role_id) AS count_of_awaited_decisions,-- How many change requests name this role as the deciding authority.
  t.current_assignment,                                                         -- The RoleAssignments id of the assignment by which this role is currently held. Deliberately a raw identifier, not a relationship: RoleAssignments already points at Roles, so an FK back would make the two mutually dependent and this rulebook must stay acyclic.
  calc_roles_current_assignment_valid_from(t.role_id) AS current_assignment_valid_from,-- Start of the currently-in-force assignment for this role.
  calc_roles_is_non_human_held(t.role_id) AS is_non_human_held,                 -- TRUE when the role's current agent is an AI agent or automated pipeline.
  calc_roles_is_ungoverned_non_human_role(t.role_id) AS is_ungoverned_non_human_role,-- TRUE when a role is pointed at a non-human agent but has no assignment row granting it.
  calc_roles_departed_assignment_count(t.role_id) AS departed_assignment_count, -- How many assignments to this role have ended.
  calc_roles_has_lost_a_holder(t.role_id) AS has_lost_a_holder,                 -- Whether anyone has ever departed this role.
  calc_roles_is_vacated_role(t.role_id) AS is_vacated_role,                     -- A role somebody departed and that nobody currently covers.
  calc_roles_ungrounded_boundary_count(t.role_id) AS ungrounded_boundary_count, -- How many boundaries constrain this role on lapsed authority.
  calc_roles_is_governed_by_lapsed_authority(t.role_id) AS is_governed_by_lapsed_authority,-- TRUE when at least one constraint on this role rests on knowledge that is no longer valid.
  calc_roles_unescalated_refusal_count(t.role_id) AS unescalated_refusal_count, -- How many refusals this role should have been told about and was not.
  calc_roles_unauthorized_enforcement_assignment_count(t.role_id) AS unauthorized_enforcement_assignment_count,-- How many current assignments of this role are unauthorized enforcement assignments.
  calc_roles_is_ungoverned_enforcement_role(t.role_id) AS is_ungoverned_enforcement_role,-- TRUE when a role that enforces controls on others is held with no recorded authorization.
  t.semantic_type_iri                                                           -- Exact semantic type IRI for the role.
FROM roles t;

-- ----------------------------------------------------------------------------
-- vw_role_assignments: Time-bounded records of agents holding roles. Maps to pro:RoleInTime and preserves assignment history instead of overwriting it.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_role_assignments CASCADE;
CREATE VIEW vw_role_assignments WITH (security_invoker = ON) AS
SELECT
  t.role_assignment_id,                                                         -- Stored logical identifier for one RoleAssignments row.
  calc_role_assignments_name(t.role_assignment_id) AS name,                     -- Human-readable calculated display alias for the RoleAssignments row.
  t.role,                                                                       -- Role held during the assignment.
  t.agent,                                                                      -- Agent holding the role.
  t.valid_from,                                                                 -- Start of the assignment's valid-time interval.
  t.valid_to,                                                                   -- End of the assignment's valid-time interval; null means open-ended.
  t.reason,                                                                     -- Rationale for the assignment or reassignment.
  t.status,                                                                     -- Active, Superseded, Planned, or Revoked.
  t.evaluation_context,                                                         -- The evaluation context this assignment's currency is judged under.
  calc_role_assignments_as_of_instant(t.role_assignment_id) AS as_of_instant,   -- The evaluation instant this assignment's currency is judged against.
  calc_role_assignments_is_current(t.role_assignment_id) AS is_current,         -- TRUE when the assignment is valid now.
  calc_role_assignments_current_agent_key(t.role_assignment_id) AS current_agent_key,-- Echoes the Agent id only while this assignment is current; empty otherwise. Lets a parent count CURRENT assignments with a single-criterion COUNTIFS, which is the only shape this transpiler translates correctly.
  calc_role_assignments_is_currently_valid(t.role_assignment_id) AS is_currently_valid,-- TRUE when this role assignment is active and has not lapsed.
  calc_role_assignments_agent_role_key(t.role_assignment_id) AS agent_role_key, -- Composite agent+role key, emitted only for currently-valid assignments.
  calc_role_assignments_has_departed(t.role_assignment_id) AS has_departed,     -- TRUE when this role assignment has ended — the agent no longer holds the role.
  calc_role_assignments_covers_now(t.role_assignment_id) AS covers_now,         -- TRUE when this assignment is both status-Active and inside its valid-time window right now.
  calc_role_assignments_role_when_covering(t.role_assignment_id) AS role_when_covering,-- Echoes the role id when this assignment is currently in force, blank otherwise.
  calc_role_assignments_agent_kind(t.role_assignment_id) AS agent_kind,         -- Whether the agent holding this assignment is Human, AIAgent, or AutomatedPipeline.
  calc_role_assignments_is_non_human_assignment(t.role_assignment_id) AS is_non_human_assignment,-- TRUE when this assignment places a non-human agent into the role.
  t.supersedes_assignment,                                                      -- The assignment this one replaced, if any.
  calc_role_assignments_predecessor_agent_kind(t.role_assignment_id) AS predecessor_agent_kind,-- Agent kind of the assignment this one superseded.
  calc_role_assignments_is_human_to_non_human_handover(t.role_assignment_id) AS is_human_to_non_human_handover,-- TRUE when this assignment handed a role from a human to a non-human agent.
  t.approving_authority_role,                                                   -- Role that approved this assignment.
  t.authorizing_change_request,                                                 -- Change request under which this assignment was approved.
  calc_role_assignments_is_unauthorized_non_human_assignment(t.role_assignment_id) AS is_unauthorized_non_human_assignment,-- TRUE when a non-human agent holds this role with no approving authority recorded at all. An authority named without a change request is still an authority; the separate WasAuthorizedByChangeRequest column carries that weaker distinction.
  calc_role_assignments_was_authorized_by_change_request(t.role_assignment_id) AS was_authorized_by_change_request,-- TRUE when this assignment's authorization is traceable to a change request, not merely to a named role. The stronger form of authorization, kept separate so the weaker one is not silently reported as unauthorized.
  calc_role_assignments_decision_count(t.role_assignment_id) AS decision_count, -- Decisions made under this assignment.
  calc_role_assignments_overridden_decision_count(t.role_assignment_id) AS overridden_decision_count,-- Decisions made under this assignment that a human corrected or reversed.
  calc_role_assignments_override_rate_percent(t.role_assignment_id) AS override_rate_percent,-- Percentage of decisions under this assignment that a human overrode.
  calc_role_assignments_predecessor_override_rate_percent(t.role_assignment_id) AS predecessor_override_rate_percent,-- Override rate of the assignment this one superseded.
  calc_role_assignments_quality_regressed_vs_predecessor(t.role_assignment_id) AS quality_regressed_vs_predecessor,-- TRUE when this assignment is overridden by humans more often than the assignment it replaced.
  calc_role_assignments_departed_role_key(t.role_assignment_id) AS departed_role_key,-- Composite-key echo: the role this assignment covered when the assignment has ended, blank otherwise.
  t.minimum_decisions_for_comparison,                                           -- The number of decisions below which an override-rate comparison is not considered evidentially meaningful for this role.
  calc_role_assignments_predecessor_decision_count(t.role_assignment_id) AS predecessor_decision_count,-- How many decisions the superseded assignment produced.
  calc_role_assignments_has_sufficient_sample(t.role_assignment_id) AS has_sufficient_sample,-- TRUE when this assignment has produced enough decisions for its override rate to mean anything.
  calc_role_assignments_predecessor_has_sufficient_sample(t.role_assignment_id) AS predecessor_has_sufficient_sample,-- TRUE when the predecessor assignment produced enough decisions to compare against.
  calc_role_assignments_comparison_is_evidentially_sound(t.role_assignment_id) AS comparison_is_evidentially_sound,-- TRUE when both sides of the override-rate comparison rest on adequate samples.
  calc_role_assignments_single_override_swing_percent(t.role_assignment_id) AS single_override_swing_percent,-- How many percentage points one additional override would move this assignment's rate. The fragility of the number.
  calc_role_assignments_quality_verdict_is_unsupported(t.role_assignment_id) AS quality_verdict_is_unsupported,-- TRUE when a quality verdict is being reported for this assignment on a sample too small to support it.
  calc_role_assignments_is_unmeasured_automation_handover(t.role_assignment_id) AS is_unmeasured_automation_handover,-- TRUE when a human-to-machine handover is operating without a statistically meaningful quality comparison behind it.
  calc_role_assignments_error_correction_count(t.role_assignment_id) AS error_correction_count,-- How many of this assignment's decisions were overridden because they were wrong.
  calc_role_assignments_error_rate_percent(t.role_assignment_id) AS error_rate_percent,-- Percentage of this assignment's decisions overridden as errors -- the override rate with reserved-judgment overrides removed.
  t.authorization_decided_at,                                                   -- When the approving authority actually granted this assignment. Empty when no authorization was ever recorded.
  t.authorization_reviewed_at,                                                  -- When the authorization for this assignment was last re-examined.
  t.authorization_review_cadence_days,                                          -- How often this assignment's authorization is promised to be re-examined.
  calc_role_assignments_has_dated_authorization(t.role_assignment_id) AS has_dated_authorization,-- TRUE when this assignment carries both a named approving authority and the date they granted it.
  calc_role_assignments_days_since_authorization_review(t.role_assignment_id) AS days_since_authorization_review,-- How long since this assignment's authorization was last re-examined.
  calc_role_assignments_authorization_is_overdue_for_review(t.role_assignment_id) AS authorization_is_overdue_for_review,-- TRUE when the promised re-examination interval has elapsed without a review.
  calc_role_assignments_is_standing_unreviewed_automation(t.role_assignment_id) AS is_standing_unreviewed_automation,-- TRUE when a currently-active non-human assignment has been running past its authorization review date.
  calc_role_assignments_is_unconditioned_automation_handover(t.role_assignment_id) AS is_unconditioned_automation_handover,-- TRUE when a human-to-machine handover was authorized with no promised review cadence at all -- granted once, permanently.
  t.max_tolerable_error_rate_percent,                                           -- The error rate at or above which this assignment must stop making decisions unaided.
  calc_role_assignments_exceeds_tolerable_error_rate(t.role_assignment_id) AS exceeds_tolerable_error_rate,-- TRUE when this assignment's error rate has reached the threshold set when it was authorized.
  calc_role_assignments_boundary_violation_count_for_assignment(t.role_assignment_id) AS boundary_violation_count_for_assignment,-- How many decisions under this assignment violated an authority boundary.
  calc_role_assignments_has_any_boundary_violation(t.role_assignment_id) AS has_any_boundary_violation,-- TRUE when any decision under this assignment crossed a boundary it was forbidden to cross.
  calc_role_assignments_has_ungrounded_governing_boundary(t.role_assignment_id) AS has_ungrounded_governing_boundary,-- TRUE when at least one boundary constraining this assignment's role rests on lapsed knowledge.
  calc_role_assignments_suspension_condition_met(t.role_assignment_id) AS suspension_condition_met,-- TRUE when any pre-declared condition requiring this assignment to stop deciding unaided has been met.
  calc_role_assignments_is_operating_under_met_suspension_conditi(t.role_assignment_id) AS is_operating_under_met_suspension_condition,-- TRUE when a suspension condition has been met and the assignment is nonetheless still active and still deciding.
  calc_role_assignments_has_declared_suspension_condition(t.role_assignment_id) AS has_declared_suspension_condition,-- TRUE when this assignment has any pre-declared condition under which it must stop at all.
  calc_role_assignments_has_approving_authority(t.role_assignment_id) AS has_approving_authority,-- TRUE when a role is recorded as having approved this assignment.
  calc_role_assignments_has_authorizing_change_request(t.role_assignment_id) AS has_authorizing_change_request,-- TRUE when a change request is recorded as the governance vehicle for this assignment.
  t.is_enforcement_role,                                                        -- Whether this role's function is to enforce controls on other agents' actions.
  calc_role_assignments_is_unauthorized_enforcement_agent(t.role_assignment_id) AS is_unauthorized_enforcement_agent,-- TRUE when a non-human agent enforces controls on others while holding no recorded authorization of its own.
  calc_role_assignments_governance_evidence_count(t.role_assignment_id) AS governance_evidence_count,-- How many independent governance artifacts back this assignment: an approving role, an authorizing change request.
  calc_role_assignments_unauthorized_enforcement_role_key(t.role_assignment_id) AS unauthorized_enforcement_role_key,-- Echoes the role only for non-human assignments nobody authorized; empty otherwise.
  t.semantic_type_iri                                                           -- Exact class IRI for the assignment event.
FROM role_assignments t;

-- ----------------------------------------------------------------------------
-- vw_communities_of_practice: Socio-technical communities that transmit and maintain procedural knowledge. Explicit ERB-PKO extension.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_communities_of_practice CASCADE;
CREATE VIEW vw_communities_of_practice WITH (security_invoker = ON) AS
SELECT
  t.community_of_practice_id,                                                   -- Stored logical identifier for one CommunitiesOfPractice row.
  calc_communities_of_practice_name(t.community_of_practice_id) AS name,        -- Human-readable calculated display alias for the CommunitiesOfPractice row.
  t.label,                                                                      -- Community's human-readable name.
  t.organization,                                                               -- Organization hosting the community.
  t.steward_role,                                                               -- Role accountable for convening and maintaining the community.
  t.purpose,                                                                    -- Shared practice and knowledge-transfer purpose.
  t.cadence,                                                                    -- Meeting or practice cadence.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM communities_of_practice t;

-- ----------------------------------------------------------------------------
-- vw_mentorships: Time-bounded apprenticeship relationships that intentionally transfer situated procedural knowledge. Explicit ERB-PKO extension.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_mentorships CASCADE;
CREATE VIEW vw_mentorships WITH (security_invoker = ON) AS
SELECT
  t.mentorship_id,                                                              -- Stored logical identifier for one Mentorships row.
  calc_mentorships_name(t.mentorship_id) AS name,                               -- Human-readable calculated display alias for the Mentorships row.
  t.community_of_practice,                                                      -- Community in which the mentorship operates.
  t.mentor_agent,                                                               -- Experienced practitioner serving as mentor.
  t.learner_agent,                                                              -- Practitioner learning the procedure.
  t.valid_from,                                                                 -- Mentorship start.
  t.valid_to,                                                                   -- Mentorship end.
  t.learning_objective,                                                         -- Procedural capability to be transferred.
  t.evidence_of_completion,                                                     -- Evidence showing completion or competence.
  t.semantic_type_iri                                                           -- Extension class IRI.
FROM mentorships t;

-- ----------------------------------------------------------------------------
-- vw_procedure_types: Controlled values used by pko:hasProcedureType.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_types CASCADE;
CREATE VIEW vw_procedure_types WITH (security_invoker = ON) AS
SELECT
  t.procedure_type_id,                                                          -- Stored logical identifier for one ProcedureTypes row.
  calc_procedure_types_name(t.procedure_type_id) AS name,                       -- Human-readable calculated display alias for the ProcedureTypes row.
  t.label,                                                                      -- Procedure type label.
  t.definition,                                                                 -- Definition and scope of the procedure type.
  t.semantic_type_iri                                                           -- Exact class IRI for procedure types.
FROM procedure_types t;

-- ----------------------------------------------------------------------------
-- vw_procedures: Abstract, discoverable procedures. Each version is represented separately in ProcedureVersions. Maps to pko:Procedure and dcat:Resource.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedures CASCADE;
CREATE VIEW vw_procedures WITH (security_invoker = ON) AS
SELECT
  t.procedure_id,                                                               -- Stored logical identifier for one Procedures row.
  calc_procedures_name(t.procedure_id) AS name,                                 -- Human-readable calculated display alias for the Procedures row.
  t.title,                                                                      -- Human-readable title; maps to dcterms:title.
  t.procedure_type,                                                             -- Procedure type; maps to pko:hasProcedureType.
  t.owner_organization,                                                         -- Organization that owns the procedure.
  t.adopted_by_organization,                                                    -- Organization that adopts the procedure; maps to pko:isAdoptedBy.
  t.purpose,                                                                    -- Desired outcome and scope of the procedure.
  t.target,                                                                     -- Thing or population on which the procedure acts; maps to pko:hasProcedureTarget.
  t.is_template,                                                                -- TRUE when the procedure is a reusable template; maps to pko:isTemplate.
  t.current_version_key,                                                        -- Current version identifier, mirrored structurally by ProcedureVersions.IsCurrent.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM procedures t;

-- ----------------------------------------------------------------------------
-- vw_procedure_versions: Versioned procedure specifications. Maps to pko:Procedure plus DCAT version relations and PKO versionNumber/newVersionMotivation/changelogDescription.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_versions CASCADE;
CREATE VIEW vw_procedure_versions WITH (security_invoker = ON) AS
SELECT
  t.procedure_version_id,                                                       -- Stored logical identifier for one ProcedureVersions row.
  calc_procedure_versions_name(t.procedure_version_id) AS name,                 -- Human-readable calculated display alias for the ProcedureVersions row.
  t.procedure,                                                                  -- Abstract procedure of which this is a version.
  t.version_number,                                                             -- Version number; maps to pko:versionNumber.
  t.title,                                                                      -- Version-specific title.
  t.status,                                                                     -- PKO procedure status individual: Draft, Validation, Approval, Approved, Deprecated, or Archived.
  t.issued_at,                                                                  -- Issue timestamp; maps to dcterms:issued.
  t.modified_at,                                                                -- Last semantic modification; maps to dcterms:modified.
  t.created_by_agent,                                                           -- Agent that created the version; maps to dcterms:creator.
  t.modified_by_agent,                                                          -- Agent that last modified the version; maps to pko:wasModifiedBy.
  t.new_version_motivation,                                                     -- Reason for the new version; maps to pko:newVersionMotivation.
  t.changelog_description,                                                      -- Semantic change description; maps to pko:changelogDescription.
  t.is_current,                                                                 -- TRUE when this is the current version.
  calc_procedure_versions_count_of_steps(t.procedure_version_id) AS count_of_steps,-- Number of steps in this version.
  calc_procedure_versions_count_of_open_knowledge_gaps(t.procedure_version_id) AS count_of_open_knowledge_gaps,-- Open knowledge gaps for this version.
  calc_procedure_versions_is_ready_for_execution(t.procedure_version_id) AS is_ready_for_execution,-- TRUE when approved, populated, and free of blocking knowledge gaps.
  calc_procedure_versions_specified_step_count(t.procedure_version_id) AS specified_step_count,-- How many steps the specification defines for this version.
  calc_procedure_versions_overdue_review_count(t.procedure_version_id) AS overdue_review_count,-- How many reviews of this procedure version are past due.
  calc_procedure_versions_open_change_request_count(t.procedure_version_id) AS open_change_request_count,-- How many change requests are open against this version.
  calc_procedure_versions_open_high_severity_gap_count(t.procedure_version_id) AS open_high_severity_gap_count,-- How many high-severity knowledge gaps are open against this version.
  calc_procedure_versions_is_fit_to_execute(t.procedure_version_id) AS is_fit_to_execute,-- TRUE when this version is approved, current on review, and carries no open change request or high-severity gap.
  calc_procedure_versions_steward_review_cadence_days(t.procedure_version_id) AS steward_review_cadence_days,-- The review cadence promised by this version's stewardship assignment, in days. Summed because a version has at most one active steward; this is the hop that lets ReviewEvents resolve the promise via a primary-key match.
  calc_procedure_versions_count_of_stewardship_assignments(t.procedure_version_id) AS count_of_stewardship_assignments,-- How many stewardship assignments of any vintage point at this version.
  calc_procedure_versions_has_any_steward(t.procedure_version_id) AS has_any_steward,-- TRUE if any stewardship assignment has ever named this version.
  calc_procedure_versions_is_live(t.procedure_version_id) AS is_live,           -- TRUE when this version is in a state where somebody could execute it.
  calc_procedure_versions_is_unstewarded(t.procedure_version_id) AS is_unstewarded,-- TRUE when no stewardship assignment names this version.
  calc_procedure_versions_is_live_and_unstewarded(t.procedure_version_id) AS is_live_and_unstewarded,-- TRUE when an executable version has nobody accountable for keeping it healthy.
  calc_procedure_versions_count_of_open_blocking_gaps(t.procedure_version_id) AS count_of_open_blocking_gaps,-- How many open blocking gaps stand against this version.
  calc_procedure_versions_has_open_blocking_gap(t.procedure_version_id) AS has_open_blocking_gap,-- TRUE when at least one open blocking gap stands against this version.
  calc_procedure_versions_is_live_with_blocking_gap(t.procedure_version_id) AS is_live_with_blocking_gap,-- TRUE when an executable version carries an unresolved blocking knowledge gap.
  calc_procedure_versions_should_not_be_executable(t.procedure_version_id) AS should_not_be_executable,-- TRUE when the model says this version is ready to execute while a blocking gap is open against it.
  calc_procedure_versions_count_of_unapproved_reliance_fragments(t.procedure_version_id) AS count_of_unapproved_reliance_fragments,-- How many unapproved claims this version is relying on.
  calc_procedure_versions_runs_on_unapproved_knowledge(t.procedure_version_id) AS runs_on_unapproved_knowledge,-- TRUE when this version depends on at least one claim the knowledge authority has not approved.
  calc_procedure_versions_count_of_overdue_gaps(t.procedure_version_id) AS count_of_overdue_gaps,-- How many acknowledged unknowns against this version have outlived their tolerance.
  calc_procedure_versions_count_of_change_requests(t.procedure_version_id) AS count_of_change_requests,-- How many change requests have ever been raised against this version.
  calc_procedure_versions_count_of_review_events(t.procedure_version_id) AS count_of_review_events,-- How many review events have ever been recorded against this version.
  calc_procedure_versions_has_governance_record(t.procedure_version_id) AS has_governance_record,-- TRUE when at least one change request or review event exists for this version.
  t.evaluation_context,                                                         -- The evaluation context this row's time-dependent witnesses are judged under.
  calc_procedure_versions_as_of_instant(t.procedure_version_id) AS as_of_instant,-- The evaluation instant this row's time-dependent witnesses are judged against.
  calc_procedure_versions_days_since_modified(t.procedure_version_id) AS days_since_modified,-- Days since this version's content was last changed.
  calc_procedure_versions_days_since_last_review(t.procedure_version_id) AS days_since_last_review,-- Days since the most recent review of this version.
  calc_procedure_versions_was_modified_since_last_review(t.procedure_version_id) AS was_modified_since_last_review,-- TRUE when the version was edited more recently than it was reviewed.
  calc_procedure_versions_modifier_is_authority(t.procedure_version_id) AS modifier_is_authority,-- The kind of agent that last modified this version.
  calc_procedure_versions_has_unwitnessed_change(t.procedure_version_id) AS has_unwitnessed_change,-- TRUE when a live version's current content postdates every review it has had.
  calc_procedure_versions_count_of_stale_fragments(t.procedure_version_id) AS count_of_stale_fragments,-- How many supporting claims have outlived this version's review cadence.
  calc_procedure_versions_knowledge_is_staler_than_cadence(t.procedure_version_id) AS knowledge_is_staler_than_cadence,-- TRUE when this version rests on at least one claim older than its own review cadence.
  calc_procedure_versions_compound_fragile_fragment_count(t.procedure_version_id) AS compound_fragile_fragment_count,-- How many compound-fragile knowledge fragments this version rests on.
  calc_procedure_versions_rests_on_compound_fragile_knowledge(t.procedure_version_id) AS rests_on_compound_fragile_knowledge,-- A live procedure version resting on at least one knowledge fragment that carries three or more decay signals.
  calc_procedure_versions_concentrated_witness_session_count(t.procedure_version_id) AS concentrated_witness_session_count,-- How many concentrated single-witness sessions underwrite this version's knowledge base.
  calc_procedure_versions_knowledge_base_is_concentrated(t.procedure_version_id) AS knowledge_base_is_concentrated,-- A live version where at least one single-witness session alone underwrites three or more of its live claims.
  calc_procedure_versions_machine_consumed_unapproved_count(t.procedure_version_id) AS machine_consumed_unapproved_count,-- How many unapproved claims this version feeds directly to software-assigned steps.
  calc_procedure_versions_feeds_unapproved_knowledge_to_machines(t.procedure_version_id) AS feeds_unapproved_knowledge_to_machines,-- A live version that hands unapproved knowledge to a step no human is positioned to review.
  calc_procedure_versions_genuinely_overdue_fragment_count(t.procedure_version_id) AS genuinely_overdue_fragment_count,-- How many of this version's claims are overdue by actual review record rather than by inference.
  calc_procedure_versions_awaited_decision_count(t.procedure_version_id) AS awaited_decision_count,-- How many decisions are pending against this live version.
  calc_procedure_versions_scoped_open_blocking_gap_count(t.procedure_version_id) AS scoped_open_blocking_gap_count,-- How many open blocking gaps belong to THIS version, correctly scoped.
  calc_procedure_versions_is_blocked_on_pending_decision(t.procedure_version_id) AS is_blocked_on_pending_decision,-- A live version carrying both an undecided change request and an open blocking gap — the gap cannot close until the decision lands.
  calc_procedure_versions_unexercised_human_gate_count(t.procedure_version_id) AS unexercised_human_gate_count,-- How many of this version's human-only gates have never been approached by software.
  calc_procedure_versions_ai_boundary_is_unevidenced(t.procedure_version_id) AS ai_boundary_is_unevidenced,-- A live version whose human-only gates rest on assertion rather than on any observed attempt by software.
  calc_procedure_versions_load_bearing_unapproved_count(t.procedure_version_id) AS load_bearing_unapproved_count,-- How many high-blast-radius unapproved claims this version rests on.
  calc_procedure_versions_unlanded_decision_count(t.procedure_version_id) AS unlanded_decision_count,-- How many decided-but-unimplemented change requests hold this version's fitness down.
  calc_procedure_versions_unrehearsed_control_entry_count(t.procedure_version_id) AS unrehearsed_control_entry_count,-- How many unrehearsed control entries exist in this procedure version.
  calc_procedure_versions_has_unrehearsed_control_entry(t.procedure_version_id) AS has_unrehearsed_control_entry,-- Whether this live version has at least one blocking control that is only reachable by a path nobody has ever walked.
  calc_procedure_versions_is_live_with_unrehearsed_control(t.procedure_version_id) AS is_live_with_unrehearsed_control,-- A version that is live for execution while carrying at least one never-rehearsed blocking control entry.
  calc_procedure_versions_cadence_breach_count(t.procedure_version_id) AS cadence_breach_count,-- How many review events on this version are past their promised cadence.
  calc_procedure_versions_is_in_cadence_breach(t.procedure_version_id) AS is_in_cadence_breach,-- Whether this version currently has at least one review event past the cadence its steward promised.
  calc_procedure_versions_has_decision_in_flight(t.procedure_version_id) AS has_decision_in_flight,-- Whether this version has at least one change request that is still open.
  calc_procedure_versions_is_unremediated_cadence_breach(t.procedure_version_id) AS is_unremediated_cadence_breach,-- A cadence breach with no open change request against the version — a broken promise with no response in motion.
  calc_procedure_versions_is_managed_cadence_breach(t.procedure_version_id) AS is_managed_cadence_breach,-- A cadence breach where a change request is at least open against the version.
  calc_procedure_versions_governance_is_silent(t.procedure_version_id) AS governance_is_silent,-- A live version with neither a change request nor a review event ever recorded against it.
  calc_procedure_versions_valid_fragment_count(t.procedure_version_id) AS valid_fragment_count,-- How many currently-valid knowledge fragments are attached to this version.
  calc_procedure_versions_still_owns_valid_knowledge(t.procedure_version_id) AS still_owns_valid_knowledge,-- Whether this version still holds at least one knowledge fragment that is currently valid.
  calc_procedure_versions_incoming_supersession_count(t.procedure_version_id) AS incoming_supersession_count,-- How many other versions declare that they supersede this one.
  calc_procedure_versions_is_still_referenced(t.procedure_version_id) AS is_still_referenced,-- Whether any other version points at this one through a supersession link.
  calc_procedure_versions_is_load_bearing_orphan(t.procedure_version_id) AS is_load_bearing_orphan,-- An unstewarded version that is still referenced by a supersession link or still owns currently-valid knowledge — nobody is accountable for it and something still depends on it.
  calc_procedure_versions_is_cleanly_retired(t.procedure_version_id) AS is_cleanly_retired,-- An unstewarded version that nothing depends on — a genuine, safe retirement.
  calc_procedure_versions_stalled_implementation_count(t.procedure_version_id) AS stalled_implementation_count,-- How many approved-but-unimplemented change requests are stalled against this version.
  calc_procedure_versions_is_held_unfit_by_landed_decisions(t.procedure_version_id) AS is_held_unfit_by_landed_decisions,-- A version reading unfit to execute specifically because approved changes have not been marked implemented.
  calc_procedure_versions_undeclared_control_kind_count(t.procedure_version_id) AS undeclared_control_kind_count,-- How many steps in this version have not declared a control kind.
  calc_procedure_versions_control_taxonomy_is_incomplete(t.procedure_version_id) AS control_taxonomy_is_incomplete,-- Whether this version contains any step whose control kind is unstated — meaning role-based and id-based control predicates cannot be trusted to cover it.
  calc_procedure_versions_has_approved_change_request(t.procedure_version_id) AS has_approved_change_request,-- TRUE when at least one change request against this version has been approved.
  calc_procedure_versions_approved_change_request_count(t.procedure_version_id) AS approved_change_request_count,-- How many change requests against this version have been approved.
  calc_procedure_versions_unwatched_unowned_control_count(t.procedure_version_id) AS unwatched_unowned_control_count,-- How many blocking controls in the model are neither computed nor owned.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM procedure_versions t;

-- ----------------------------------------------------------------------------
-- vw_procedure_version_links: Directed links between versioned procedures. Maps to dcat:previousVersion/dcat:hasVersion and pko:nextVersion.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_version_links CASCADE;
CREATE VIEW vw_procedure_version_links WITH (security_invoker = ON) AS
SELECT
  t.procedure_version_link_id,                                                  -- Stored logical identifier for one ProcedureVersionLinks row.
  calc_procedure_version_links_name(t.procedure_version_link_id) AS name,       -- Human-readable calculated display alias for the ProcedureVersionLinks row.
  t.previous_procedure_version,                                                 -- Earlier version.
  t.next_procedure_version,                                                     -- Later version.
  t.relation_iri,                                                               -- Exact version relation IRI.
  t.change_summary,                                                             -- Summary of semantic change across the edge.
  calc_procedure_version_links_superseded_version_key(t.procedure_version_link_id) AS superseded_version_key-- Echoes the superseded (previous) version id for rows that express a next-version relation. Supersession is carried by RelationIri here, not by a separate link-kind column.
FROM procedure_version_links t;

-- ----------------------------------------------------------------------------
-- vw_procedure_status_changes: Lifecycle events that move a procedure version between PKO statuses. Maps to pko:ChangeOfStatus, fromStatus, toStatus, and prov:atTime.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_procedure_status_changes CASCADE;
CREATE VIEW vw_procedure_status_changes WITH (security_invoker = ON) AS
SELECT
  t.procedure_status_change_id,                                                 -- Stored logical identifier for one ProcedureStatusChanges row.
  calc_procedure_status_changes_name(t.procedure_status_change_id) AS name,     -- Human-readable calculated display alias for the ProcedureStatusChanges row.
  t.procedure_version,                                                          -- Procedure version whose status changed.
  t.from_status,                                                                -- Previous PKO status.
  t.to_status,                                                                  -- New PKO status.
  t.changed_at,                                                                 -- Time of change; maps to prov:atTime.
  t.changed_by_agent,                                                           -- Agent responsible for the change.
  t.motivation,                                                                 -- Reason for changing status.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM procedure_status_changes t;

-- ----------------------------------------------------------------------------
-- vw_steps: Version-scoped units of work. Atomic steps map to pplan:Step; composite steps map to pplan:MultiStep. The specification is never conflated with execution.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_steps CASCADE;
CREATE VIEW vw_steps WITH (security_invoker = ON) AS
SELECT
  t.step_id,                                                                    -- Stored logical identifier for one Steps row.
  calc_steps_name(t.step_id) AS name,                                           -- Human-readable calculated display alias for the Steps row.
  t.procedure_version,                                                          -- Procedure version containing the step; maps to pko:hasStep/pplan:isStepOfPlan.
  t.step_number,                                                                -- Stable sequence label; maps to pko:stepNumber.
  t.title,                                                                      -- Human-readable step title.
  t.step_kind,                                                                  -- Atomic or MultiStep.
  t.assigned_role,                                                              -- Role responsible for the step.
  calc_steps_assigned_role_label(t.step_id) AS assigned_role_label,             -- Resolved role label.
  calc_steps_assigned_agent_kind(t.step_id) AS assigned_agent_kind,             -- Current role-filler category.
  t.instruction,                                                                -- Normative step instruction.
  t.expected_duration_minutes,                                                  -- Expected duration represented as an OWL-Time duration in semantic projections.
  t.expertise_level,                                                            -- PKO expertise level: Junior, Senior, Expert, or Master.
  t.requires_human_confirmation,                                                -- TRUE when a human must confirm the step; maps to pko:wasConfirmedBy at execution.
  calc_steps_blocking_requirement_count(t.step_id) AS blocking_requirement_count,-- How many blocking requirements the specification attaches to this step.
  calc_steps_stale_binding_count(t.step_id) AS stale_binding_count,             -- How many operational bindings for this step are currently outside their freshness SLA.
  calc_steps_authoritative_stale_count(t.step_id) AS authoritative_stale_count, -- How many authoritative bindings for this step are currently stale.
  calc_steps_available_exception_count(t.step_id) AS available_exception_count, -- How many active exceptions the specification defines for this step.
  calc_steps_declared_verification_count(t.step_id) AS declared_verification_count,-- How many verifications the specification declares for this step.
  calc_steps_is_preparation_step(t.step_id) AS is_preparation_step,             -- TRUE for steps whose assigned role produces the work product rather than reviewing it.
  calc_steps_is_approval_step(t.step_id) AS is_approval_step,                   -- TRUE for steps whose assigned role is an approval authority.
  calc_steps_stale_authoritative_binding_count(t.step_id) AS stale_authoritative_binding_count,-- Number of authoritative bindings for this step that are past their freshness SLA.
  calc_steps_inputs_are_fresh(t.step_id) AS inputs_are_fresh,                   -- TRUE when no authoritative binding for this step is stale.
  calc_steps_is_software_assigned(t.step_id) AS is_software_assigned,           -- TRUE when this step is specified to be performed by software rather than a person.
  calc_steps_is_human_approval_gate(t.step_id) AS is_human_approval_gate,       -- TRUE for the steps that exist specifically to place a human commitment between drafting and delivery.
  calc_steps_gate_held_by_human(t.step_id) AS gate_held_by_human,               -- TRUE when a designated approval gate is in fact assigned to a human role.
  calc_steps_binding_boundary_count(t.step_id) AS binding_boundary_count,       -- Number of authority boundaries currently binding at this step.
  calc_steps_assigned_role_is_ungoverned(t.step_id) AS assigned_role_is_ungoverned,-- Whether this step's assigned role is a non-human role with no governing assignment.
  calc_steps_unusable_binding_count(t.step_id) AS unusable_binding_count,       -- Number of bindings at this step that are unapproved or stale.
  calc_steps_all_sources_usable(t.step_id) AS all_sources_usable,               -- TRUE when every binding at this step is an approved, fresh source.
  t.control_kind,                                                               -- What kind of control this step is: Preparation, Approval, LegalReview, Verification, Extraction, Publication, Retrospective, or None. That policy-04 is a legal review is a property OF policy-04, not of a formula that happens to name it; storing it as data makes downstream predicates portable to procedures that do not exist yet.
  calc_steps_unwarranted_boundary_count(t.step_id) AS unwarranted_boundary_count,-- How many boundaries governing this step are being enforced without a valid ratifying claim.
  calc_steps_is_governed_by_unwarranted_boundary(t.step_id) AS is_governed_by_unwarranted_boundary,-- Whether this step's constraints on machine authority rest on a claim that is no longer valid.
  calc_steps_software_execution_count(t.step_id) AS software_execution_count,   -- How many times a software agent has actually executed this step.
  calc_steps_has_been_approached_by_software(t.step_id) AS has_been_approached_by_software,-- Whether any software agent has ever executed this step.
  calc_steps_is_unexercised_human_gate(t.step_id) AS is_unexercised_human_gate, -- A human-only approval gate that no software agent has ever attempted — the control is asserted, not demonstrated.
  calc_steps_is_demonstrated_human_gate(t.step_id) AS is_demonstrated_human_gate,-- A human gate that software has actually reached and that a human nevertheless held.
  calc_steps_unexercised_gate_version_key(t.step_id) AS unexercised_gate_version_key,-- Composite-key echo: this step's procedure version when the step is an unexercised human gate, blank otherwise.
  calc_steps_has_declared_control_kind(t.step_id) AS has_declared_control_kind, -- Whether this step declares what kind of control it is.
  calc_steps_undeclared_control_version_key(t.step_id) AS undeclared_control_version_key,-- Composite-key echo: this step's procedure version when the step has no declared control kind, blank otherwise.
  calc_steps_approval_step_is_software_assigned(t.step_id) AS approval_step_is_software_assigned,-- An approval-kind step whose assigned role is currently held by an AI agent or automated pipeline.
  calc_steps_unwitnessed_blocking_count(t.step_id) AS unwitnessed_blocking_count,-- How many blocking controls bound to this step have no computed witness.
  t.semantic_type_iri                                                           -- Exact P-Plan class IRI.
FROM steps t;

-- ----------------------------------------------------------------------------
-- vw_step_transitions: Directed control-flow edges represented as first-class pko:Transition instances with fromStep/toStep and next/alternative/fallback semantics.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_transitions CASCADE;
CREATE VIEW vw_step_transitions WITH (security_invoker = ON) AS
SELECT
  t.step_transition_id,                                                         -- Stored logical identifier for one StepTransitions row.
  calc_step_transitions_name(t.step_transition_id) AS name,                     -- Human-readable calculated display alias for the StepTransitions row.
  t.procedure_version,                                                          -- Procedure version whose control flow owns the transition.
  t.from_step,                                                                  -- Source step; maps to pko:fromStep.
  t.to_step,                                                                    -- Destination step; maps to pko:toStep.
  t.transition_kind,                                                            -- Next, Alternative, or Fallback.
  t.condition,                                                                  -- Condition under which the edge is taken.
  t.priority,                                                                   -- Evaluation priority when several outgoing edges exist.
  calc_step_transitions_is_recovery_path(t.step_transition_id) AS is_recovery_path,-- TRUE when this transition is a non-default path taken because something went wrong.
  calc_step_transitions_count_of_from_step_executions(t.step_transition_id) AS count_of_from_step_executions,-- How many times the step this transition leaves from has actually been executed.
  calc_step_transitions_count_of_to_step_executions(t.step_transition_id) AS count_of_to_step_executions,-- How many times the step this transition arrives at has actually been executed.
  calc_step_transitions_has_reachable_origin(t.step_transition_id) AS has_reachable_origin,-- TRUE when the origin step of this transition has been executed at least once.
  calc_step_transitions_has_reachable_target(t.step_transition_id) AS has_reachable_target,-- TRUE when the destination step of this transition has been executed at least once.
  calc_step_transitions_is_never_exercised(t.step_transition_id) AS is_never_exercised,-- TRUE when at least one end of this transition has never appeared in any step execution.
  calc_step_transitions_is_untested_recovery_path(t.step_transition_id) AS is_untested_recovery_path,-- TRUE for a Fallback or Alternative transition whose endpoints show no execution evidence.
  calc_step_transitions_count_of_observed_traversals(t.step_transition_id) AS count_of_observed_traversals,-- How many times this exact transition has actually been traversed.
  calc_step_transitions_has_been_traversed(t.step_transition_id) AS has_been_traversed,-- TRUE when this transition has been walked at least once.
  calc_step_transitions_is_unwalked_recovery_path(t.step_transition_id) AS is_unwalked_recovery_path,-- TRUE for a Fallback/Alternative transition with zero recorded traversals.
  calc_step_transitions_target_blocking_requirement_count(t.step_transition_id) AS target_blocking_requirement_count,-- How many blocking requirements are attached to the step this transition lands on.
  calc_step_transitions_target_carries_blocking_control(t.step_transition_id) AS target_carries_blocking_control,-- Whether the destination step of this transition carries at least one blocking control.
  calc_step_transitions_is_unrehearsed_control_entry(t.step_transition_id) AS is_unrehearsed_control_entry,-- A recovery path that has never been traversed and that leads into a step carrying a blocking control.
  calc_step_transitions_unrehearsed_control_version_key(t.step_transition_id) AS unrehearsed_control_version_key,-- Composite-key echo: this transition's procedure version when it is an unrehearsed control entry, blank otherwise.
  t.semantic_type_iri                                                           -- Exact PKO class IRI.
FROM step_transitions t;

-- ----------------------------------------------------------------------------
