-- ----------------------------------------------------------------------------
-- vw_step_tools: Many-to-many Step/Tool semantics normalized into an ERB junction table.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_step_tools CASCADE;
CREATE VIEW vw_step_tools WITH (security_invoker = ON) AS
SELECT
